export class RateLimiter {
  private tokens: number;
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private lastRefill: number;

  constructor(maxTokens: number, refillRate: number) {
    this.maxTokens = Math.max(0, maxTokens);
    this.tokens = this.maxTokens;
    this.refillRate = Math.max(0, refillRate);
    this.lastRefill = Date.now();
  }

  tryConsume(): boolean {
    this.refill();
    if (this.tokens > 0) {
      this.tokens -= 1;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefill = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefill;
    if (elapsed <= 0 || this.refillRate <= 0) {
      this.lastRefill = now;
      return;
    }

    const newTokens = (elapsed * this.refillRate) / 1000;
    if (newTokens > 0) {
      this.tokens = Math.min(this.maxTokens, this.tokens + newTokens);
    }

    this.lastRefill = now;
  }
}

export interface Record {
  id: number;
  name: string;
  category: string;
  value: number;
}

export type Stage = (records: Record[]) => Record[];
export type Filter = (record: Record) => boolean;

export class Pipeline {
  private stages: Stage[] = [];
  private filters: Filter[] = [];

  addStage(stage: Stage): this {
    this.stages.push(stage);
    return this;
  }

  addFilter(filter: Filter): this {
    this.filters.push(filter);
    return this;
  }

  run(records: Record[]): Record[] {
    let result = [...records];
    if (this.filters.length > 0) {
      result = result.filter((record) => this.filters.every((filter) => filter(record)));
    }
    for (const stage of this.stages) {
      result = stage(result);
    }
    return result;
  }
}

export function andFilter(...filters: Filter[]): Filter {
  return (record: Record) => filters.every((filter) => filter(record));
}

export function orFilter(...filters: Filter[]): Filter {
  return (record: Record) => filters.some((filter) => filter(record));
}

export function notFilter(filter: Filter): Filter {
  return (record: Record) => !filter(record);
}

export function doubleValues(records: Record[]): Record[] {
  return records.map((r) => ({ ...r, value: r.value * 2 }));
}

export interface CronSchedule {
  minutes: number[];
  hours: number[];
  daysOfMonth: number[];
  months: number[];
  daysOfWeek: number[];
  original: string;
}

export class CronParseError extends Error {
  constructor(message: string, public field?: string) {
    super(message);
    this.name = 'CronParseError';
  }
}

type FieldSpec = {
  name: string;
  min: number;
  max: number;
};

const FIELD_SPECS: FieldSpec[] = [
  { name: 'minute', min: 0, max: 59 },
  { name: 'hour', min: 0, max: 23 },
  { name: 'day-of-month', min: 1, max: 31 },
  { name: 'month', min: 1, max: 12 },
  { name: 'day-of-week', min: 0, max: 6 },
];

function throwFieldError(message: string, field?: string): never {
  throw new CronParseError(message, field);
}

function isPositiveIntegerString(value: string): boolean {
  return /^[0-9]+$/.test(value);
}

function parseNumber(token: string, spec: FieldSpec): number {
  if (!isPositiveIntegerString(token)) {
    throwFieldError(`Invalid value "${token}" in ${spec.name}`, spec.name);
  }
  const n = Number(token);
  if (!Number.isInteger(n) || n < spec.min || n > spec.max) {
    throwFieldError(`Value "${token}" out of range for ${spec.name}`, spec.name);
  }
  return n;
}

function expandRange(start: number, end: number, step: number): number[] {
  const result: number[] = [];
  for (let n = start; n <= end; n += step) result.push(n);
  return result;
}

function parseField(expression: string, spec: FieldSpec): number[] {
  const parts = expression.split(',');
  if (parts.length === 0) {
    throwFieldError(`Empty ${spec.name} field`, spec.name);
  }

  const values: number[] = [];

  for (const part of parts) {
    if (part.length === 0) {
      throwFieldError(`Invalid list syntax in ${spec.name}`, spec.name);
    }

    let segmentValues: number[] = [];

    if (part === '*') {
      segmentValues = expandRange(spec.min, spec.max, 1);
    } else if (part.startsWith('*/')) {
      const stepStr = part.slice(2);
      const step = parseNumber(stepStr, spec);
      if (step <= 0) {
        throwFieldError(`Step must be greater than 0 in ${spec.name}`, spec.name);
      }
      segmentValues = expandRange(spec.min, spec.max, step);
    } else if (part.includes('/')) {
      const [rangePart, stepPart, ...extra] = part.split('/');
      if (extra.length > 0 || !rangePart || !stepPart) {
        throwFieldError(`Invalid step syntax in ${spec.name}`, spec.name);
      }
      const step = parseNumber(stepPart, spec);
      if (step <= 0) {
        throwFieldError(`Step must be greater than 0 in ${spec.name}`, spec.name);
      }
      const rangeMatch = rangePart.match(/^([0-9]+)-([0-9]+)$/);
      if (!rangeMatch) {
        throwFieldError(`Invalid range syntax in ${spec.name}`, spec.name);
      }
      const start = parseNumber(rangeMatch[1], spec);
      const end = parseNumber(rangeMatch[2], spec);
      if (start > end) {
        throwFieldError(`Range start greater than end in ${spec.name}`, spec.name);
      }
      segmentValues = expandRange(start, end, step);
    } else if (part.includes('-')) {
      const [startStr, endStr, ...extra] = part.split('-');
      if (extra.length > 0 || !startStr || !endStr) {
        throwFieldError(`Invalid range syntax in ${spec.name}`, spec.name);
      }
      const start = parseNumber(startStr, spec);
      const end = parseNumber(endStr, spec);
      if (start > end) {
        throwFieldError(`Range start greater than end in ${spec.name}`, spec.name);
      }
      segmentValues = expandRange(start, end, 1);
    } else {
      segmentValues = [parseNumber(part, spec)];
    }

    for (const value of segmentValues) {
      if (!values.includes(value)) values.push(value);
    }
  }

  values.sort((a, b) => a - b);
  return values;
}

export function parseCron(expression: string): CronSchedule {
  if (typeof expression !== 'string') {
    throw new CronParseError('Expression must be a string');
  }

  const trimmed = expression.trim();
  const fields = trimmed.length === 0 ? [] : trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new CronParseError('Cron expression must have exactly 5 fields');
  }

  const [minutes, hours, daysOfMonth, months, daysOfWeek] = fields.map((field, index) =>
    parseField(field, FIELD_SPECS[index])
  );

  return {
    minutes,
    hours,
    daysOfMonth,
    months,
    daysOfWeek,
    original: expression,
  };
}

export interface Item {
  id: string;
  name: string;
  status: "active" | "archived";
  createdAt: number;
  updatedAt: number;
}

export interface Request {
  method: "GET" | "POST" | "PUT" | "DELETE" | string;
  headers: Record<string, string>;
  params: Record<string, string>;
  body?: unknown;
}

export interface Response {
  status: number;
  body: unknown;
}

const store = new Map<string, Item>();

export function resetStore(): void {
  store.clear();
}

export function getStore(): Map<string, Item> {
  return store;
}

function createResponse(status: number, success: boolean, payload: Record<string, unknown>): Response {
  return { status, body: { success, ...payload } };
}

function errorResponse(status: number, error: string): Response {
  return createResponse(status, false, { error });
}

function authorize(req: Request): Response | null {
  const token = req.headers["authorization"];
  if (!token) return errorResponse(401, "Authorization required");
  if (token !== "Bearer valid-token") return errorResponse(401, "Invalid token");
  return null;
}

function getBodyRecord(body: unknown): Record<string, unknown> | null {
  if (!body || typeof body !== "object") return null;
  return body as Record<string, unknown>;
}

function requireBody(body: unknown): { ok: true; data: Record<string, unknown> } | { ok: false; response: Response } {
  const data = getBodyRecord(body);
  if (!data) return { ok: false, response: errorResponse(400, "Request body is required") };
  return { ok: true, data };
}

function requireIdParam(req: Request): { ok: true; id: string } | { ok: false; response: Response } {
  const id = req.params["id"];
  if (!id) return { ok: false, response: errorResponse(400, "Validation failed: id parameter is required") };
  return { ok: true, id };
}

function handleGet(req: Request): Response {
  const id = req.params["id"];
  if (!id) return createResponse(200, true, { data: Array.from(store.values()) });
  const item = store.get(id);
  return item ? createResponse(200, true, { data: item }) : errorResponse(404, "Item not found");
}

function handlePost(req: Request): Response {
  const bodyResult = requireBody(req.body);
  if (!bodyResult.ok) return bodyResult.response;
  const data = bodyResult.data;
  if (!(data["name"] && typeof data["name"] === "string")) {
    return errorResponse(400, "Validation failed: name is required");
  }
  const id = data["id"] as string | undefined;
  if (id && store.has(id)) return errorResponse(409, "Item already exists");
  const newId = id || `item-${Date.now()}`;
  const now = Date.now();
  const item: Item = {
    id: newId,
    name: data["name"] as string,
    status: "active",
    createdAt: now,
    updatedAt: now,
  };
  store.set(newId, item);
  return createResponse(201, true, { data: item });
}

function handlePut(req: Request): Response {
  const bodyResult = requireBody(req.body);
  if (!bodyResult.ok) return bodyResult.response;
  const idResult = requireIdParam(req);
  if (!idResult.ok) return idResult.response;
  const item = store.get(idResult.id);
  if (!item) return errorResponse(404, "Item not found");
  const data = bodyResult.data;
  const updated: Item = { ...item, updatedAt: Date.now() };
  if (data["name"] && typeof data["name"] === "string") updated.name = data["name"] as string;
  if (data["status"] && (data["status"] === "active" || data["status"] === "archived")) {
    updated.status = data["status"] as "active" | "archived";
  }
  store.set(idResult.id, updated);
  return createResponse(200, true, { data: updated });
}

function handleDelete(req: Request): Response {
  const idResult = requireIdParam(req);
  if (!idResult.ok) return idResult.response;
  const item = store.get(idResult.id);
  if (!item) return errorResponse(404, "Item not found");
  store.delete(idResult.id);
  return createResponse(200, true, { data: { deleted: idResult.id } });
}

export function handleRequest(req: Request): Response {
  const authError = authorize(req);
  if (authError) return authError;
  if (req.method === "GET") return handleGet(req);
  if (req.method === "POST") return handlePost(req);
  if (req.method === "PUT") return handlePut(req);
  if (req.method === "DELETE") return handleDelete(req);
  return errorResponse(405, "Method not allowed");
}

import { describe, it, expect } from "vitest";
import { deepMerge } from "../../starter/deep-merge.js";

describe("deepMerge", () => {
  it("merges nested plain objects recursively without mutating inputs", () => {
    const target = {
      a: 1,
      nested: {
        b: 2,
        deep: {
          c: 3,
        },
      },
    };
    const source = {
      nested: {
        b: 20,
        deep: {
          d: 4,
        },
      },
      e: 5,
    };

    const result = deepMerge(target, source);

    expect(result).toEqual({
      a: 1,
      nested: {
        b: 20,
        deep: {
          c: 3,
          d: 4,
        },
      },
      e: 5,
    });
    expect(result).not.toBe(target);
    expect(result.nested).not.toBe(target.nested);
    expect(result.nested.deep).not.toBe(target.nested.deep);
    expect(target).toEqual({
      a: 1,
      nested: {
        b: 2,
        deep: {
          c: 3,
        },
      },
    });
    expect(source).toEqual({
      nested: {
        b: 20,
        deep: {
          d: 4,
        },
      },
      e: 5,
    });
  });

  it("replaces arrays entirely with a shallow clone of the source array", () => {
    const target = {
      arr: [1, 2, 3],
      nested: {
        list: ["a"],
      },
    };
    const source = {
      arr: [4, 5],
      nested: {
        list: ["x", "y"],
      },
    };

    const result = deepMerge(target, source);

    expect(result.arr).toEqual([4, 5]);
    expect(result.arr).not.toBe(source.arr);
    expect(result.arr).not.toBe(target.arr);
    expect(result.nested.list).toEqual(["x", "y"]);
    expect(result.nested.list).not.toBe(source.nested.list);
    expect(result.nested.list).not.toBe(target.nested.list);
  });

  it("clones Date objects and does not share references", () => {
    const date = new Date("2024-01-02T03:04:05.678Z");
    const target = {
      createdAt: new Date("2020-01-01T00:00:00.000Z"),
      nested: {
        updatedAt: new Date("2021-02-03T04:05:06.789Z"),
      },
    };
    const source = {
      createdAt: date,
      nested: {
        updatedAt: new Date("2022-03-04T05:06:07.890Z"),
      },
    };

    const result = deepMerge(target, source);

    expect(result.createdAt).toEqual(date);
    expect(result.createdAt).not.toBe(date);
    expect(result.nested.updatedAt).toEqual(source.nested.updatedAt);
    expect(result.nested.updatedAt).not.toBe(source.nested.updatedAt);
    expect(result.createdAt).not.toBe(target.createdAt);
    expect(result.nested.updatedAt).not.toBe(target.nested.updatedAt);
  });

  it("supports symbol keys in both target and source", () => {
    const sym1 = Symbol("sym1");
    const sym2 = Symbol("sym2");

    const target = {
      [sym1]: { keep: true, deep: { x: 1 } },
      plain: 1,
    };
    const source = {
      [sym1]: { deep: { y: 2 } },
      [sym2]: "new",
    };

    const result = deepMerge(target, source);

    expect(result[sym1]).toEqual({ keep: true, deep: { x: 1, y: 2 } });
    expect(result[sym1]).not.toBe(target[sym1]);
    expect(result[sym2]).toBe("new");
    expect(Object.getOwnPropertySymbols(result)).toEqual(expect.arrayContaining([sym1, sym2]));
    expect(result.plain).toBe(1);
  });

  it("skips undefined in source and preserves target values", () => {
    const target = {
      a: 1,
      nested: {
        b: 2,
      },
      arr: [1, 2],
    };
    const source = {
      a: undefined,
      nested: {
        b: undefined,
      },
      arr: undefined,
    };

    const result = deepMerge(target, source);

    expect(result).toEqual(target);
    expect(result.a).toBe(1);
    expect(result.nested).toEqual({ b: 2 });
    expect(result.arr).toEqual([1, 2]);
  });

  it("replaces target values with null from source", () => {
    const target = {
      a: 1,
      nested: {
        b: 2,
      },
      arr: [1, 2],
    };
    const source = {
      a: null,
      nested: null,
      arr: null,
    };

    const result = deepMerge(target, source);

    expect(result).toEqual({
      a: null,
      nested: null,
      arr: null,
    });
  });

  it("skips forbidden keys and protects against prototype pollution", () => {
    const target = {
      safe: 1,
      nested: {
        ok: true,
      },
    };

    const source = Object.create(null);
    source.safe = 2;
    source.__proto__ = { polluted: true };
    source.constructor = { prototype: { polluted: true } };
    source.prototype = { polluted: true };
    source.nested = {
      ok: false,
    };

    const result = deepMerge(target, source);

    expect(result.safe).toBe(2);
    expect(result.nested).toEqual({ ok: false });
    expect(({} as Record<string, unknown>).polluted).toBeUndefined();
    expect(Object.prototype).not.toHaveProperty("polluted");
    expect(result).not.toHaveProperty("constructor");
    expect(result).not.toHaveProperty("prototype");
    expect(result).not.toHaveProperty("__proto__");
  });

  it("handles plain object sources when target value is not a plain object", () => {
    const target = {
      value: 123,
      date: new Date("2020-01-01T00:00:00.000Z"),
      arr: [1],
    };
    const source = {
      value: { nested: true },
      date: { notADate: true },
      arr: { notAnArray: true },
    };

    const result = deepMerge(target, source);

    expect(result.value).toEqual({ nested: true });
    expect(result.date).toEqual({ notADate: true });
    expect(result.arr).toEqual({ notAnArray: true });
  });

  it("merges deeply through multiple levels and preserves untouched branches", () => {
    const target = {
      level1: {
        left: {
          a: 1,
          b: 2,
        },
        right: {
          c: 3,
        },
      },
      top: "keep",
    };
    const source = {
      level1: {
        left: {
          b: 20,
          d: 4,
        },
        right: undefined,
      },
    };

    const result = deepMerge(target, source);

    expect(result).toEqual({
      level1: {
        left: {
          a: 1,
          b: 20,
          d: 4,
        },
        right: {
          c: 3,
        },
      },
      top: "keep",
    });
    expect(result.level1.left).not.toBe(target.level1.left);
    expect(result.level1.right).toBe(target.level1.right);
    expect(result.top).toBe("keep");
  });

  it("handles a mix of primitives and objects in the same merge", () => {
    const target = {
      n: 1,
      s: "hello",
      bool: true,
      obj: {
        x: 1,
      },
    };
    const source = {
      n: 2,
      s: "world",
      bool: false,
      obj: {
        y: 2,
      },
    };

    const result = deepMerge(target, source);

    expect(result).toEqual({
      n: 2,
      s: "world",
      bool: false,
      obj: {
        x: 1,
        y: 2,
      },
    });
  });
});
